def wait_until(condition_func, timeout_steps=5, poll_steps=1):
    """
    Poll condition_func every poll_steps until it returns truthy or timeout_steps reached.
    Returns the truthy value or raises TimeoutError.
    """
    elapsed = 0
    while elapsed <= timeout_steps:
        result = condition_func()
        if result:
            return result
        elapsed += poll_steps
    raise TimeoutError(f"Condition not met after {timeout_steps} steps")

# Simulate a page that loads elements after some steps
step = [0]
page_elements = {}  # Simulates DOM elements appearing over time

def simulate_load():
    """Simulate a page loading elements step by step."""
    step[0] += 1
    if step[0] >= 2:
        page_elements["header"] = {"tag": "h1", "text": "Welcome"}
    if step[0] >= 4:
        page_elements["login_form"] = {"tag": "form", "id": "login"}

def find_element(selector):
    """Check if element exists in page_elements."""
    simulate_load()
    return page_elements.get(selector)

# Test waiting for elements
print("Waiting for header...")
try:
    element = wait_until(lambda: find_element("header"), timeout_steps=5)
    print(f"Found: {element['text']}")
except TimeoutError as e:
    print(f"Timeout: {e}")

print("Waiting for login form...")
try:
    element = wait_until(lambda: find_element("login_form"), timeout_steps=5)
    print(f"Found: form id={element['id']}")
except TimeoutError as e:
    print(f"Timeout: {e}")

# Test timeout case
print("Waiting for missing element...")
try:
    wait_until(lambda: find_element("missing_elem"), timeout_steps=3)
except TimeoutError as e:
    print(f"Timeout: {e}")
